import React from 'react';

const smallChopsData = [
  {
    id: 1,
    name: "The Starter Mark",
    price: "15,000",
    contents: "7 Samosas, 7 Spring rolls, 15 Puff Puff, 10 Mosa (or 5 Money Bags), 4 Chicken",
    image: "/images/starter.jpg" 
  },
  {
    id: 2,
    name: "Signature Platter",
    price: "25,000",
    contents: "A luxury high-volume curation. Perfect for gifting, office meetings, or premium sharing.",
    image: "/images/signature.jpg" // Make sure to add this image!
  },
  {
    id: 3,
    name: "The Owambe Pack",
    price: "150,000",
    contents: "Full Event Catering service for 50 People. The ultimate party selection for luxury gatherings.",
    image: "/images/premium.jpg" 
  }
];

function Menu() {
  return (
    <section style={{ backgroundColor: '#000', color: '#fff', padding: '80px 20px' }}>
      
      <h2 style={{ 
        color: '#D4AF37', 
        textAlign: 'center', 
        letterSpacing: '8px', 
        textTransform: 'uppercase', 
        fontSize: '1.6rem', 
        marginBottom: '60px' 
      }}>
        The Collections
      </h2>

      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', 
        justifyContent: 'center', 
        gap: '30px', 
        maxWidth: '1200px', 
        margin: '0 auto' 
      }}>
        
        {smallChopsData.map((pack) => (
          <div key={pack.id} style={{ 
            backgroundColor: '#050505', 
            borderRadius: '15px', 
            overflow: 'hidden', 
            border: '1px solid #111',
            boxShadow: '0 10px 30px rgba(0,0,0,0.5)',
            display: 'flex',
            flexDirection: 'column'
          }}>
            
            <img 
              src={pack.image} 
              alt={pack.name} 
              style={{ width: '100%', height: '250px', objectFit: 'cover', filter: 'brightness(0.8)' }} 
            />

            <div style={{ padding: '25px', flexGrow: 1, display: 'flex', flexDirection: 'column', justifyContent: 'space-between' }}>
              <div>
                <h3 style={{ color: '#D4AF37', fontSize: '1.3rem', marginBottom: '15px' }}>
                  {pack.name}
                </h3>
                
                <p style={{ 
                  color: '#E07A5F', 
                  fontSize: '0.85rem', 
                  letterSpacing: '1px', 
                  fontWeight: 'bold', 
                  marginBottom: '25px',
                  lineHeight: '1.5',
                  borderLeft: '2px solid #D4AF37',
                  paddingLeft: '12px'
                }}>
                  {pack.contents}
                </p>
              </div>
              
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '10px' }}>
                <p style={{ color: '#fff', fontSize: '1.5rem', fontWeight: 'bold', margin: 0 }}>
                  ₦{pack.price.toLocaleString()}
                </p>
                
                <button style={{ 
                  backgroundColor: '#D4AF37', 
                  color: '#000', 
                  border: 'none', 
                  padding: '10px 20px', 
                  borderRadius: '5px', 
                  fontSize: '0.75rem', 
                  fontWeight: 'bold',
                  cursor: 'pointer',
                  textTransform: 'uppercase'
                }}>
                  Order
                </button>
              </div>
            </div>
          </div>
        ))}

      </div>
    </section>
  );
}

export default Menu;
